import { RcTable, sleep, Actions, LinkButton } from '@xsahxl/ui';
import axios from 'axios';
import { Button, Badge } from '@alicloud/console-components';
import '@alicloud/console-components/dist/wind.css';
import Cookie from 'js-cookie';

Cookie.set('aliyun_lang', 'zh');

const Demo = () => {
  const [refreshIndex, setRefreshIndex] = useState(0);
  const columns = [
    {
      key: 'InstanceName',
      title: '\u5B9E\u4F8B\u540D\u79F0',
      dataIndex: 'InstanceName',
    },
    {
      key: 'Address',
      title: 'IP\u5730\u5740',
      dataIndex: 'Address',
    },
    {
      key: 'CreationTime',
      title: '\u521B\u5EFA\u65F6\u95F4',
      dataIndex: 'CreationTime',
      sortable: true,
    },
    {
      key: 'Status',
      title: '\u72B6\u6001',
      dataIndex: 'Status',
    },
    {
      title: '\u64CD\u4F5C',
      cell: () => (
        <Actions>
          <LinkButton>\u8BE6\u60C5</LinkButton>
          <LinkButton>\u7F16\u8F91</LinkButton>
          <LinkButton disabled>\u5220\u9664</LinkButton>
        </Actions>
      ),
    },
  ];
  const search = {
    children: <Button>\u81EA\u5B9A\u4E49\u5185\u5BB9</Button>,
    defaultDataIndex: 'name',
    defaultSelectedDataIndex: 'name',
    options: [
      {
        label: '\u5B9E\u4F8B\u540D\u79F0',
        dataIndex: 'name',
        template: 'input',
        templateProps: {
          placeholder: '\u6309\u5B9E\u4F8B\u540D\u79F0\u641C\u7D22',
        },
        defaultValue: 'abc',
      },
      {
        label: '\u7F51\u7EDC\u7C7B\u578B',
        dataIndex: 'type',
        template: 'select',
        templateProps: {
          placeholder: '\u8BF7\u9009\u62E9\u7F51\u7EDC\u7C7B\u578B',
          dataSource: [
            { label: 'A', value: 'a' },
            { label: 'B', value: 'b' },
            { label: 'C', value: 'c' },
            { label: 'D', value: 'd' },
          ],
        },
        defaultValue: 'c',
      },
      {
        label: '\u4ED8\u8D39\u7C7B\u578B',
        dataIndex: 'pay',
        template: 'multiple',
        templateProps: {
          placeholder: '\u8BF7\u9009\u62E9\u4ED8\u8D39\u7C7B\u578B',
          dataSource: [
            { label: 'A', value: 'a' },
            { label: 'B', value: 'b' },
            { label: 'C', value: 'c' },
            { label: 'D', value: 'd' },
          ],
        },
        defaultValue: ['a', 'd'],
      },
    ],
  };
  const fetchData = async params => {
    console.log('params', params);
    await sleep(500);
    const res = await axios.get('https://table-lacaqljjvb.cn-chengdu.fcapp.run', {
      params,
    });
    console.log(res);
    return {
      data: res.data.data.Instances.Instance,
      total: res.data.data.TotalCount,
    };
  };
  return (
    <RcTable
      className="cc"
      style={{ color: '#333' }}
      columns={columns}
      fetchData={fetchData}
      refreshIndex={refreshIndex}
      recordCurrent
      showRefreshButton
      operation={
        <Button type="primary" onClick={() => setRefreshIndex(Date.now())}>
          \u521B\u5EFA\u5E94\u7528
        </Button>
      }
      search={search}
      primaryKey="InstanceId"
      selection={({ selectedRowKeys }: { selectedRowKeys: any[] }) => {
        return (
          <Badge count={selectedRowKeys.length}>
            <Button disabled={selectedRowKeys.length === 0}>Delete</Button>
          </Badge>
        );
      }}
    />
  );
};

